function packMarkdown(key, pack) {
  const lines = pack.entries.map((entry) =>
    existsSync(entry) ? `- ${entry}` : `- ${entry} (missing — create it)`,
  );
  return `${GENERATED_HEADER}

# Pack: ${pack.title}

Read in order:

${lines.join('\n')}
`;
}

export function buildKnowledge({
  graphsOnly = false,
  packsOnly = false,
  incremental = false,
} = {}) {
  const inventory = buildInventory();
  if (incremental && existsSync('.ai/manifest.json')) {
    const previous = JSON.parse(readFileSync('.ai/manifest.json', 'utf8'));
    if (JSON.stringify(previous.files) === JSON.stringify(inventory)) {
      console.log('knowledge:build --incremental: canonical sources unchanged; skipping.');
      return;
    }
  }
  if (!packsOnly) {
    writeGenerated('.ai/graphs/modules.json', JSON.stringify(moduleGraph(), null, 2));
    writeGenerated('.ai/graphs/ownership.json', JSON.stringify(ownershipGraph(), null, 2));
    writeGenerated('.ai/graphs/layers.json', JSON.stringify(layersGraph(), null, 2));
  }
  if (!graphsOnly) {
    for (const [key, pack] of Object.entries(PACKS)) {
      writeGenerated(`.ai/packs/${key}.md`, packMarkdown(key, pack));
    }
  }
  if (!graphsOnly && !packsOnly) {
    writeGenerated('.ai/BOOTSTRAP.md', bootstrapMarkdown());
    writeGenerated('.ai/README.md', readmeMarkdown());
    writeGenerated('.ai/authority-order.md', authorityOrderMarkdown());
    writeGenerated('.ai/risk-lanes.md', riskLanesMarkdown());
    writeGenerated('.ai/context-router-spec.md', contextRouterSpecMarkdown());
    const canonicalCount = Object.keys(inventory).length;
    writeGenerated(
      '.ai/reports/knowledge-report.json',
      JSON.stringify(
        {
          generated: true,
          governanceVersion: GOVERNANCE_VERSION,
          canonicalFileCount: canonicalCount,
          packs: Object.keys(PACKS).sort(),
        },
        null,
        2,
      ),
    );
    writeGenerated(
      '.ai/manifest.json',
      JSON.stringify(
        {
          generated: true,
          governanceVersion: GOVERNANCE_VERSION,
          entrypoint: '.ai/BOOTSTRAP.md',
          canonicalRoots: [
            'rules',
            'skills',
            'agents',
            'context',
            'memory',
            'architecture/adrs',
            'docs',
          ],
          files: inventory,
        },
        null,
        2,
      ),
    );
  }
  console.log('knowledge:build completed.');
}
